INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-1', 2, 89, 'Viprin UFO', 'nothawkyre', 'notTheGolden', '107238250', 'Retro 1.9 styled extreme that only uses the UFO gamemode. Gameplay is much harder than it looks due to the unpredictable click-patterns and sketchy routes. Includes an upbeat Waterflame song and references to Pacman and Flappy Bird levels.', 'https://levelthumbs.prevter.me/thumbnail/107238250', 0, '682504', '-Arcade Punk- by Waterflame', '["2.2", "Long", "Timings", "Chokepoints", "Memory", "Ufo"]', '25/08/07', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-2', 3, 117, 'Destruction 19', 'bosjoker', 'razsta4ax', '99495619', NULL, 'https://levelthumbs.prevter.me/thumbnail/99495619', 0, '465681', '~NK~ VS TI:. Amity by TIMarbury', '["2.2", "Long", "Fast-paced", "Timings", "Learny", "High Cps", "Flow"]', '26/02/02', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-4', 5, 144, 'ConClusion', 'DreamZoneGD', 'BrowarKedawar', '96471171', 'The final and hardest level of the ConTrilogy. This level holds nothing back and utilizes memory to its fullest while including flashbacks from both ConTroller and ConFusion. The wave part is known for being very intimidating to approach and can be considered one of the most intense parts of a memory level. Now, can you escape your mind and conclude this nightmare once and for all?
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-5', 6, 151, 'Crimson Planet', 'TrueOmega', 'rWooshi', '45866767', 'Legendary former top 1 with an intense dubstep song and a loose otherworldly theme. Incredibly reminiscent of early 2.1, being started only months after 2.1''s release. Includes Terron''s iconic part repurposed from Yatagarasu and a modern endscreen. Took too long to get rated. Do not abbreviate on Discord (seriously).', 'https://levelthumbs.prevter.me/thumbnail/45866767', 0, '530913', 'Wonderpunch by Xtrullor', '["Long", "High Cps", "2.1", "Wave"]', '25/07/10', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-6', 7, 157, 'Cognition', 'Endlevel', 'nSwish', '57600307', 'Iconic claustrophobic former top 3 extreme with an old fashioned song featuring Charlie Chaplin''s speech from The Great Dictator. Known for its incredibly precise gameplay, monochromatic visuals and dark atmosphere.', 'https://levelthumbs.prevter.me/thumbnail/57600307', 0, NULL, 'Violence... by ChristianMossuto', '["2.1", "Long", "Fast-paced", "Timings", "Precision", "Nong"]', '25/12/25', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-7', 8, 160, 'Cosmic Cyclone', 'APTeamOfficial', 'DoSh7t', '76159410', 'APTeam''s standout project, acting as the sequel to Sonic Wave. Consists of exceedingly bright effects and flashy space-themed designs similarly to Sonic Wave Infinity. Took 4 years to be created and verified, starting in 2017. ', 'https://levelthumbs.prevter.me/thumbnail/76159410', 0, '725417', 'Hydra by F-777', '["2.1", "Long", "Circles", "Wave", "High Cps", "Chokepoints"]', '25/01/10', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-8', 9, 167, 'RUST', 'neigefeu', 'Keir', '71912451', 'A solo timing-based extreme formerly in the Top 20 which became highly popular among demonlist players for its accessibility. It combines sharp movements, non-blending glow and a washed-out colour scheme to create a gritty atmosphere, hence its name. Its gameplay takes heavy inspiration from KrmaL and crohn44, and is notable for its usage of double clicks and a long stress test at the end.', 'https://levelthumbs.prevter.me/thumbnail/71912451', 0, '823812', 'Creo - Outlaw by CreoMusic', '["2.1", "Long", "Clicksync", "Timings", "Chokepoints", "Learny", "Nerve Control"]', '25/12/21', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-9', 10, 173, 'Cobwebs', 'NineDice', 'Cursed', '82172844', NULL, 'https://levelthumbs.prevter.me/thumbnail/82172844', 0, NULL, 'Cerebral Cobweb (okuu remix) (edited) by OkuU-o', '["2.2", "Medium", "Nong", "Fast-paced", "Learny", "High Cps"]', '25/10/23', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-10', 11, 180, 'Shardscapes', 'ItzKiba', 'kiseta', '79997992', 'Minimalist-style timing-based extreme using only the robot gamemode. Its gameplay is notable for its usage of spike corner jumps and multi-activated orbs, and its decoration combines parallax, enter/exit effects and a calm Creo song to create a dream-like atmosphere.', 'https://levelthumbs.prevter.me/thumbnail/79997992', 0, '800646', 'Creo - Slow Down by CreoMusic', '["2.1", "Long", "Timings", "Robot", "Slow-paced"]', '25/12/25', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-11', 12, 205, 'Bloodlust', 'knobbelboy', 'knobbelboy', '42584142', 'Legendary former Top 1 and remake of Bloodbath, expanding on its predecessor with a minute-long extension of fast-paced gameplay as well as many changes to existing gameplay and an overhauled visual style. Had a monumental verification taking Knobbelboy over 1.5 years, 120k attempts and 1000 hours of playtime, which for its time was completely unheard of.', 'https://levelthumbs.prevter.me/thumbnail/42584142', 0, '467339', 'At the Speed of Light by Dimrain47', '["2.1", "Xl", "Ship", "Fast-paced", "Chokepoints"]', '26/01/29', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-12', 13, 210, 'X84', 'Xav', 'Xav', '110791899', '', 'https://levelthumbs.prevter.me/thumbnail/110791899', 0, NULL, 'Another Xronixle for Xronial Xero by Camellia', '["2.2", "Learny", "Fast-paced", "Wave", "Duals", "High Cps"]', '26/02/06', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-13', 14, 216, 'Nhelv', 'guillester', 'guillester', '68353244', NULL, 'https://levelthumbs.prevter.me/thumbnail/68353244', 0, NULL, 'ALESDA! - Lost by alexizgd', '["2.1", "Long", "Nong", "Learny", "Memory", "Gimmicky", "Nerve Control"]', '25/04/08', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-14', 15, 226, 'Aronia', 'Exen', 'Kotamon', '60564010', NULL, 'https://levelthumbs.prevter.me/thumbnail/60564010', 0, '591740', 'Cosmic Dreamer by TheColdSpirit', '["2.1", "Long", "Learny", "Fast-paced", "Clicksync", "High Cps", "Duals"]', '23/05/06', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-15', 16, 254, 'Arctic Lights', 'Metalface221', 'Metalface221', '52919433', 'A notoriously difficult nine circles level that was the top 1 hardest nine circles level when it was verified. This was a remake to Hyper Paracosm and is themed after the color pale blue. For a long time, this was known as the list demon many would beat first, like Cobwebs and Cognition. Best known for its awkward wave gameplay and some difficult chokepoints, especially at 36-48% and 58-69%.', 'https://levelthumbs.prevter.me/thumbnail/52919433', 0, '431573', '~NK~ Untitled beat by Rukkus', '["2.1", "Long", "Circles", "Fast-paced", "Wave"]', '26/02/18', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-16', 18, 293, 'AKIRA', 'Eridani', 'Solus', '88421468', NULL, 'https://levelthumbs.prevter.me/thumbnail/88421468', 0, '862247', 'NEON THRILLS by lukhash', '["2.1", "Long", "Fast-paced"]', '24/08/20', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-17', 17, 291, 'ConTroller', 'DreamZoneGD', 'DreamZoneGD', '79619086', 'DreamZone''s first solo level and the first of the ConTrilogy. This factory themed level contains heavy amounts of memory with tons of fakes similar to some levels from the 1.9 era. The factory heats up during the drop and becomes very dynamic, so try not to get too controlled with the level''s fast movements.
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-18', 19, 311, 'Sink', 'Awedsy', 'nac', '77255632', 'A purple and orange extreme demon combining modern creating techniques and ideas with 1.9 editor limitations in the 1.9GDPS. Its gameplay mostly revolves around clicksync with the first two sections bearing a big chunk of the level''s difficulty.', 'https://levelthumbs.prevter.me/thumbnail/77255632', 0, NULL, 'Goldenrod Game Corner Remix by EpicRPGRemixes', '["1.9ps", "Long", "Nong", "Timings", "Clicksync", "Ship", "Wave"]', '25/11/30', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-19', 20, 312, 'FIFTY THREE', 'Vlacc', 'Vlacc', '90539291', 'A fast-paced, visually simple level, where the drop''s gameplay is in mirror mode and cycles through all the gamemodes in chronological order (though skipping the robot). Due to a lot of effort put into balancing, it has become very enjoyed amongst its victors. One of the two Vlacc levels starting out as "layout53", the other being Cloud Nine.', 'https://levelthumbs.prevter.me/thumbnail/90539291', 0, '681649', 'PUNYASO - Popcorn (ColBreakz Remix) by ColBreakz', '["2.1", "Long", "Timings", "Clicksync", "Mirror", "Fast-paced", "Nerve Control"]', '26/02/14', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-20', 21, 315, 'Rage', 'nSwish', 'nSwish', '53878361', 'A high-CPS level with 7 sections, one for each gamemode. The colour scheme for each section is based on the gamemode’s portal.', 'https://levelthumbs.prevter.me/thumbnail/53878361', 0, NULL, 'RAGE NO. I by DesoloZ', '["2.1", "Long", "Nong", "High Cps", "Ship"]', '26/01/04', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-21', 22, 317, 'Sonic Wave Rebirth', 'Serponge', 'Moosh', '68688849', '2.0 remake of Sonic Wave with near identical gameplay and effects that have aged to varying degrees. Despite being extremely similar it is notably less enjoyable on average.', 'https://levelthumbs.prevter.me/thumbnail/68688849', 0, '574484', 'F-777 - Sonic Blaster by F-777', '["Xl", "Wave", "Circles", "2.0"]', '26/01/14', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-22', 23, 318, 'Sonic Wave', 'Sunix', 'Sunix', '26681070', 'One of the most famous extreme demons of all time, with a rich history and many remakes. An iconic blue circles level with three separate wave parts and a hard ball part in the predrop. Member of the first RGB trilogy.', 'https://levelthumbs.prevter.me/thumbnail/26681070', 0, '574484', 'F-777 - Sonic Blaster by F-777', '["2.0", "Xl", "Wave", "Circles", "Chokepoints", "Nerve Control"]', '25/07/01', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-23', 24, 328, 'Yatagarasu', 'TrusTa', 'Kandai', '28220417', 'One of the most iconic 2.0 megacollabs, and one of the most memorable Top 1s of all time despite only dethroning Sonic Wave for a short time.  Contains 3 minutes of stressful gameplay from start to finish, including an incredibly difficult predrop, and chokepoints throughout, including Michigun''s famous "bird click". Member of the first RGB trilogy.', 'https://levelthumbs.prevter.me/thumbnail/28220417', 0, '490479', 'Flawless Wings of Yatagarasu by Gls', '["2.0", "Xl", "Timings", "Chokepoints", "Old Swing", "Nerve Control"]', '26/02/20', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-24', 25, 333, 'Shmarley Ville', 'Renn241', 'Zipi', '81535535', NULL, 'https://levelthumbs.prevter.me/thumbnail/81535535', 0, '982372', 'CATCH THAT EMERALD! by SlyceCaik', '["2.1", "Long", "Learny", "High Cps", "Timings", "Fast-paced"]', '25/06/29', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-25', 26, 345, 'Molten Core', 'Janucha', 'Lucidium', '68414488', NULL, 'https://levelthumbs.prevter.me/thumbnail/68414488', 0, '658430', 'NK - Fairydust (Ravitex Remix) by Ravitex', '["2.1", "Long", "Wave", "Circles", "Fast-paced", "High Cps", "Learny"]', '25/12/02', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-26', 27, 384, 'Stygian Machinery', 'TeamE12', 'Laniakea', '64554339', NULL, 'https://levelthumbs.prevter.me/thumbnail/64554339', 0, '674353', 'Dystopia [3k EP] by MafiaPineapple', '["2.1", "Xl", "Learny", "Nerve Control", "Wave", "Ship"]', '25/11/23', NULL, NULL, NULL, NULL);
