INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-28', 29, 389, 'Catalyze', 'ZephiroX', 'MrSpaghetti', '50333567', NULL, 'https://levelthumbs.prevter.me/thumbnail/50333567', 0, '794165', 'Catalyze by Kolkian', '["2.1", "Long", "Fast-paced", "Timings", "Nerve Control", "Wave"]', '22/09/06', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-29', 30, 429, 'Adelucid', 'Arraegen', 'Arraegen', '111368620', 'A gimmicky and fast-paced Extreme Demon utilizing Passable blocks, orb-based gameplay and uniquely ethereal decoration. Currently the hardest "full solo" level in the game, with the creator having finished the entire song, gameplay, decoration and verification by himself.', 'https://levelthumbs.prevter.me/thumbnail/111368620', 0, '1324445', 'Adelucid by TheRealMannyHeffley', '["2.2", "Long", "Learny", "Ship", "Duals"]', '25/08/02', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-30', 32, 479, 'Mind Control', 'Deadlox', 'xander', '77487419', NULL, 'https://levelthumbs.prevter.me/thumbnail/77487419', 0, '219635', '-Control: Mind- by Waterflame', '["2.1", "Long", "Timings", "Learny", "Memory", "High Cps", "Ship"]', '22/06/27', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-31', 31, 449, 'Artificial Ascent', 'ViPriN', 'combi', '27122654', 'An extremely popular former top 1 megacollab made in 2.0, initially hosted by LmAnubis and finished by Viprin. The level contains a variety of fast-paced gameplay parts made by 18 different creators, spanning almost 2 and a half minutes. It went on to have multiple remakes and sequels, becoming the first installment of the Technology Trilogy.', 'https://levelthumbs.prevter.me/thumbnail/27122654', 0, '63082', 'Surface by Dimrain47', '["2.0", "Xl", "Fast-paced"]', '22/09/14', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-32', 33, 480, 'Quantum Processing', 'Riot', 'rampage', '38235367', 'A superbuffed remake of the main level Blast Processing, with gameplay by Riot and Hinds and a short section by Zobros.', 'https://levelthumbs.prevter.me/thumbnail/38235367', 0, '-17', 'Blast Processing by Waterflame', '["2.0", "Long", "Timings", "Chokepoints", "Slow-paced", "Ufo", "Wave"]', '26/02/25', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-33', 34, 485, 'Black Blizzard', 'KrmaL', 'KrmaL', '34057654', 'Former top 10 solo level by KrmaL. Initially this level was harder and being verified in secret, but after the level was leaked through a hack, KrmaL verified and released a nerfed version. This level got Creo well known within the community. The gameplay is gimmicky and extremely predrop carried.', 'https://levelthumbs.prevter.me/thumbnail/34057654', 0, '709578', 'Dimension by hyperdemented', '["2.1", "Long", "Fast-paced", "Timings", "Duals"]', '22/03/31', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-34', 35, 488, 'Ethereal Artifice', 'Zeroya', 'Mycrafted', '58252259', 'Generally well recieved 2.1 megacollab with a red and green color scheme. It''s a fast-paced XL level spanning just over two minutes in length.', 'https://levelthumbs.prevter.me/thumbnail/58252259', 0, '193466', 'Rose At Twilight by NemesisTheory', '["2.1", "Xl", "High Cps", "Fast-paced", "Nerve Control", "Wave"]', '25/12/21', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-35', 36, 509, 'BuTiTi III', 'JonathanGD', 'PancakeKnight', '57433866', 'Jonathan''s almost cancelled threequel to his infamous Butiti series. The level is XXL with second half carried balancing, learny gameplay and interesting coin routes.', 'https://levelthumbs.prevter.me/thumbnail/57433866', 0, '684651', 'nano love by meganeko', '["2.1", "Chokepoints", "Timings", "Duals", "Xl"]', '25/10/15', NULL, NULL, NULL, NULL);
