INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-43', 44, 649, 'Blade of Justice', 'Manix648', 'RicoLP', '35448603', 'An extremely high quality 2.0 level by two of the most talented creators at the time. Features multiple iconic parts such as the black hole UFO and asymmetrical dual, and is generally harder at the start and end. Formerly an upcoming top 1 before receiving a large nerfdate making it more accessible and enjoyable.', 'https://levelthumbs.prevter.me/thumbnail/35448603', 0, '167229', 'Goukisan - Betrayal of Fear by Goukisan', '["2.0", "Xl", "Ufo", "Nerve Control", "Duals"]', '20/07/28', NULL, NULL, NULL, NULL);
INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-44', 45, 651, 'Paranoid Android', 'Alass', '^Isabunny^', '111731617', 'A 5 and a half minute level to the tune of the Radiohead song of the same name. It takes on a very progression-based approach to represent its song - the level spends its first half building up to its climax with fast-paced gameplay and flashy visuals before ending off on a much slower 2 minute-long timing-based ending.', 'https://levelthumbs.prevter.me/thumbnail/111731617', 0, NULL, 'paranoid android (demo) cover by jambrother2', '["2.2", "Xxl+", "Nong", "Timings", "Chokepoints", "Slow-paced", "Nerve Control"]', '25/09/13', NULL, NULL, NULL, NULL);
