INSERT INTO levels (id, hkgd_rank, aredl_rank, name, creator, verifier, level_id, description, thumbnail, list_points, song_id, song_name, tags, date_added, pack, gddl_tier, nlw_tier, pemonlist_rank) VALUES ('hkgd-48', 49, 728, 'Bloodbath', 'Riot', 'Riot', '10565740', 'One of the most popular extreme demons in the game, and the second level of the Apocalyptic trilogy. This level was known for being the hardest of its time, due to the ship parts being near impossible at the time. Nowadays a pretty tough level, with Michigun''s part being arguably the most difficult.', 'https://levelthumbs.prevter.me/thumbnail/10565740', 0, '467339', 'At the Speed of Light by Dimrain47', '["1.9", "Long", "Timings", "Ship"]', '27/18/04', NULL, NULL, NULL, NULL);
